func hookBadgeClass(hookType string) string {
	switch hookType {
	case "before":
		return "badge-info"
	case "after":
		return "badge-success"
	case "on-mutate":
		return "badge-warning"
	default:
		return "badge-ghost"
	}
}

func formatHooksBytes(b int64) string {
	switch {
	case b >= 1024*1024:
		return fmt.Sprintf("%.1f MB", float64(b)/(1024*1024))
	case b >= 1024:
		return fmt.Sprintf("%.1f KB", float64(b)/1024)
	default:
		return fmt.Sprintf("%d B", b)
	}
}

